KMP 演算法透過預處理模式串的 π 陣列（最長 border 長度），實現文字串中模式串的線性時間匹配。適用於子串匹配、旋轉字串、重複子串等場景。模板題為 28. 找出字串中第一個匹配項的下標。

**C++ 模板**：

```cpp
// 建立 KMP 前綴陣列（pi 陣列）
vector<int> kmpBuild(const string& pattern) {
    int n = pattern.size();
    vector<int> pi(n);
    for (int i = 1; i < n; i++) {
        int j = pi[i - 1];
        while (j > 0 && pattern[i] != pattern[j]) {
            j = pi[j - 1];
        }
        if (pattern[i] == pattern[j]) {
            j++;
        }
        pi[i] = j;
    }
    return pi;
}

// KMP 匹配：在 text 中找 pattern 的所有出現位置
vector<int> kmpSearch(const string& text, const string& pattern) {
    vector<int> pi = kmpBuild(pattern);
    vector<int> res;
    int j = 0;
    for (int i = 0; i < (int)text.size(); i++) {
        while (j > 0 && text[i] != pattern[j]) {
            j = pi[j - 1];
        }
        if (text[i] == pattern[j]) {
            j++;
        }
        if (j == (int)pattern.size()) {
            res.push_back(i - j + 1);
            j = pi[j - 1];
        }
    }
    return res;
}
```

Z 函式計算字尾與原串的最長公共字首（LCP），可用於子串匹配。構造 `pattern + s`，若 $z[m+i] \geq m$，則匹配成功。可替代 KMP，適用於 28、2223 等題。

**C++ 模板**：

```cpp
// Z 函式：z[i] = s[i..] 與 s 的最長公共字首長度
vector<int> zFunction(const string& s) {
    int n = s.size();
    vector<int> z(n, 0);
    int l = 0, r = 0;
    for (int i = 1; i < n; i++) {
        if (i < r) {
            z[i] = min(r - i, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            z[i]++;
        }
        if (i + z[i] > r) {
            l = i;
            r = i + z[i];
        }
    }
    return z;
}
```

Manacher 演算法線上性時間內求出所有迴文中心的最長迴文串。可用於判斷子串是否為迴文、求最長迴文子串、最短迴文串構造等。模板題為 5. 最長迴文子串。

**C++ 模板**：

```cpp
// Manacher：求每個中心的最長迴文半徑
vector<int> manacher(const string& s) {
    string t = "#";
    for (char c : s) {
        t += c;
        t += '#';
    }
    int n = t.size();
    vector<int> p(n, 0);
    int c = 0, r = 0;
    for (int i = 0; i < n; i++) {
        // 如果 i 在當前回文右邊界內，利用對稱性初始化 p[i]
        if (i < r) {
            p[i] = min(r - i, p[2 * c - i]);
        }
        // 中心擴展：嘗試擴展以 i 為中心的迴文半徑
        while (i - p[i] - 1 >= 0 && i + p[i] + 1 < n && t[i - p[i] - 1] == t[i + p[i] + 1]) {
            p[i]++;
        }
        // 更新迴文右邊界 r 和對應的中心 c
        if (i + p[i] > r) {
            c = i;
            r = i + p[i];
        }
    }
    return p;
}
```

使用多項式雜湊（單模/雙模）快速比較子串。適用於子串匹配、重複子串、最長公共子串等。推薦先做 2156. 查詢給定雜湊值的子串。可二分比較字典序。

**C++ 模板**：

```cpp
// 字串雜湊（多項式雜湊）
struct StringHash {
    static const long long kMod = 1e9 + 7, kBase = 131;
    vector<long long> h, pw;
    StringHash(const string& s) {
        int n = s.size();
        h.resize(n + 1);
        pw.resize(n + 1);
        h[0] = 0;
        pw[0] = 1;
        for (int i = 0; i < n; i++) {
            h[i + 1] = (h[i] * kBase + s[i]) % kMod;
            pw[i + 1] = pw[i] * kBase % kMod;
        }
    }
    long long get(int l, int r) {
        return (h[r + 1] - h[l] * pw[r - l + 1] % kMod + kMod * 2) % kMod;
    }
};
```

求字串迴圈同構串中字典序最小者。透過雙指標維護候選起點，每次排除 k+1 個位置，總複雜度 $O(n)$。模板題為 899. 有序佇列（k=1）。

**C++ 模板**：

```cpp
// 最小表示法：找到字串旋轉中字典序最小的起始位置
int minRepresentation(const string& s) {
    int n = s.size(), i = 0, j = 1, k = 0;
    while (i < n && j < n && k < n) {
        int diff = s[(i + k) % n] - s[(j + k) % n];
        // 字元相同，繼續比較下一個位置
        if (diff == 0) {
            k++;
        }
        // i 位置的字元較大，移動 i 指標跳過這段
        else if (diff > 0) {
            i += k + 1;
            k = 0;
        }
        // j 位置的字元較大，移動 j 指標跳過這段
        else {
            j += k + 1;
            k = 0;
        }
        // 避免 i 和 j 指向同一位置
        if (i == j) {
            j++;
        }
    }
    return min(i, j);
}
```

AC 自動機 = 字典樹 + KMP。用於多模式串匹配。可替代字串雜湊，適用於 1032、1408 等題。

**C++ 模板**：

```cpp
// AC 自動機 = 字典樹 + KMP fail 指標
struct AhoCorasick {
    vector<array<int, 26>> ch;   // 字典樹的邊
    vector<int> fail;             // fail 指標（類似 KMP 的 next 陣列）
    vector<int> cnt;              // 每個節點結尾的模式串數量

    // 建立新節點
    int newNode() {
        ch.push_back({});
        fail.push_back(0);
        cnt.push_back(0);
        ch.back().fill(0);
        return ch.size() - 1;
    }

    // 建構子：初始化根節點
    AhoCorasick() {
        newNode();
    }

    // 插入模式串到字典樹
    void insert(const string& s) {
        int cur = 0;
        for (char c : s) {
            int u = c - 'a';
            // 如果該邊不存在，建立新節點
            if (!ch[cur][u]) {
                ch[cur][u] = newNode();
            }
            cur = ch[cur][u];
        }
        cnt[cur]++;  // 標記模式串結尾
    }

    // 建立 fail 指標（類似 KMP 的預處理）
    void build() {
        queue<int> q;
        // 第一層節點的 fail 指標都指向根節點
        for (int i = 0; i < 26; i++) {
            if (ch[0][i]) {
                q.push(ch[0][i]);
            }
        }
        // BFS 建立 fail 指標
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (int i = 0; i < 26; i++) {
                if (ch[u][i]) {
                    // 節點存在：設定 fail 指標並加入佇列
                    fail[ch[u][i]] = ch[fail[u]][i];
                    q.push(ch[u][i]);
                } else {
                    // 節點不存在：直接指向 fail 位置的對應邊（路徑壓縮）
                    ch[u][i] = ch[fail[u]][i];
                }
            }
        }
    }
};
```

後綴陣列可求字典序最大/最小子串、最長公共子串等。後綴自動機支援子串計數、本質不同子串數等。適用於 1163、1754、1044 等題。

**C++ 模板**：

```cpp
// 後綴陣列（倍增法 O(n log n)）
vector<int> buildSa(const string& s) {
    int n = s.size();
    vector<int> sa(n), rank(n), tmp(n);
    iota(sa.begin(), sa.end(), 0);  // 初始化 sa 為 [0, 1, 2, ..., n-1]

    // 初始化 rank 為字元的 ASCII 值
    for (int i = 0; i < n; i++) {
        rank[i] = s[i];
    }

    // 倍增排序：每次比較長度為 k 的子串
    for (int k = 1; k < n; k <<= 1) {
        // 比較函數：先比較前 k 個字元，再比較後 k 個字元
        auto cmp = [&](int a, int b) {
            if (rank[a] != rank[b]) {
                return rank[a] < rank[b];
            }
            int ra = a + k < n ? rank[a + k] : -1;
            int rb = b + k < n ? rank[b + k] : -1;
            return ra < rb;
        };

        // 根據比較函數排序後綴陣列
        sort(sa.begin(), sa.end(), cmp);

        // 更新 rank：相同的後綴給相同的 rank
        tmp[sa[0]] = 0;
        for (int i = 1; i < n; i++) {
            tmp[sa[i]] = tmp[sa[i - 1]] + (cmp(sa[i - 1], sa[i]) ? 1 : 0);
        }
        rank = tmp;

        // 如果所有後綴都已區分，提前退出
        if (rank[sa[n - 1]] == n - 1) {
            break;
        }
    }
    return sa;
}
```

預處理每個位置後最近的字元下標，用於快速判斷子序列匹配。適用於 792、514、2014 等題。

**C++ 模板**：

```cpp
// 子序列自動機：nxt[i][c] = 位置 i 之後最近的字元 c 的位置
vector<array<int, 26>> buildSubseqAutomaton(const string& s) {
    int n = s.size();
    vector<array<int, 26>> nxt(n + 1);
    nxt[n].fill(n);
    for (int i = n - 1; i >= 0; i--) {
        nxt[i] = nxt[i + 1];
        nxt[i][s[i] - 'a'] = i;
    }
    return nxt;
}
```

